const e=JSON.parse('{"key":"v-633cb0ed","path":"/learn-vue/reactivity/proxy.html","title":"响应式的基础Proxy","lang":"zh-CN","frontmatter":{"title":"响应式的基础Proxy","date":"2023-02-23T15:27:39.000Z","tag":["vue"],"category":["vue"],"description":"vue3.x中的Proxy","footer":true},"headers":[{"level":3,"title":"Prxoy 与 Reflect","slug":"prxoy-与-reflect","link":"#prxoy-与-reflect","children":[]},{"level":3,"title":"怎么代理对象","slug":"怎么代理对象","link":"#怎么代理对象","children":[]},{"level":3,"title":"baseHandles","slug":"basehandles","link":"#basehandles","children":[]}],"git":{"createdTime":1677137987000,"updatedTime":1677919873000,"contributors":[{"name":"wangmaoquan","email":"1782976211@qq.com","commits":3}]},"readingTime":{"minutes":6.5,"words":1951},"filePathRelative":"learn-vue/reactivity/proxy.md","localizedDate":"2023年2月23日","excerpt":"<h3> Prxoy 与 Reflect</h3>\\n<p>什么是 <code>Proxy</code> ? 简单来说, 就是使用 <code>Proxy</code> 可以创建一个代理对象, 它能够实现对<strong>其他对象</strong>的代理, 也就是说 <code>Proxy</code> 只能代理对象, 所以对于<code>字符串</code>, <code>数字</code>, <code>布尔值</code>等, 无法代理. 那么<code>代理</code> 是什么? 所谓代理, 指的是对一个对象的<strong>基本语义</strong>的代理, 允许我们<code>拦截</code>并<code>重新定义</code>对一个对象的基本操作</p>"}');export{e as data};
